answer1 = input()
answer2 = input()

if len(answer1) != len(answer2):
    print("No")
else:
    is_anagram = True
    for char in answer1:
        found = False
        for j in range(len(answer2)):
            if char == answer2[j]:
                found = True
                answer2 = answer2[:j] + answer2[j+1:]  
                break

        if not found:
            is_anagram = False
            break
    if is_anagram:
        print("Yes")
    else:
        print("No")
